VALUES
  ('locality-814ced5a-moex-00266', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '行政權某些運作領域涉及高度專業性，且應與各政治勢力保持一定距離，因此有設置獨立機關之必要。下 列何者為我國現行制度下的獨立機關？', '["國軍退除役官兵輔導委員會", "消費者保護委員會", "中央選舉委員會", "公務人員保障暨培訓委員會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00267', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '近代國家組成要素之一為國民，我國憲法第 3條即明文規定「具有中華民國國籍者為中華民國國民」。關 於我國現行國籍制度之敘述，下列何者正確？', '["國籍法並未直接否認雙重國籍，因此雙重國籍者於我國亦得依法擔任各類公職", "大陸地區人民來臺後於臺灣地區設籍時起，依法即可擔任公務人員", "僅有具中華民國國籍之國民，始得依法加入全民健康保險", "外國人申請歸化我國，必須於法定期間內提出喪失原有國籍證明"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00268', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '政黨為現代民主政治運作不可或缺的元素，其協助形成國民政治意志，並推薦候選人參加公職人員選舉。 關於我國政黨相關制度設計之敘述，下列何者正確？', '["以政黨比例代表制產生之立法委員，於其喪失黨籍後，即喪失立委席次", "政黨為特殊性質之人民團體，故各政黨主席須向監察院申報其自身財產", "內政部經調查後認為某政黨有危害我國憲政秩序時，得強制解散該政黨", "我國政黨得受內政部特許經營電視媒體，以宣揚理念或從事活動宣傳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00269', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '新加坡於1965年成為共和國。人民行動黨（People’sActionParty，PAP）是該國自1959年成為自治邦後， 首次於選舉中勝出並持續執政迄今之唯一執政黨。2020年7月中，PAP在國會選舉中贏得83席（得票率 達61.24%），持續以超過2/3的席次執政。依據上述所言，新加坡政黨生態較符合下列何者？', '["非競爭型：一黨專政制", "競爭型：兩黨制", "競爭型：多黨制", "競爭型：一黨獨大制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00270', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '我國少年事件處理法於2019年大幅修正，下列有關本次修法之敘述何者正確？', '["犯重罪之少年得令入少年監獄服刑", "少年假釋之服刑比例由二分之一調整為三分之一", "兒童犯罪者不再適用少年保護處分", "未滿14歲觸犯重罪者不得宣告有期徒刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00271', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '司法院大法官對於失聯移工經查獲後受強制收容處分之解釋，下列敘述何者正確？', '["外國人並非我國憲法的基本權利主體，僅能主張法律層級保障的人身自由", "受收容處分的外國人不服該處分，僅得向內政部移民署申訴，而無法提請法院裁決", "失聯移工遭查獲後，皆須進行強制收容", "若暫時收容期間將屆滿，而內政部移民署倘認有繼續收容之必要，須移送法院依法審查決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00272', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '因應新冠肺炎（COVID-19）傳染疫情，自海外返國之民眾須接受14日之居家檢疫。接受檢疫者於檢疫期 間，則可依法每日領取新臺幣1,000元。試問，該給付的法律性質屬於下列何者？', '["民事賠償", "行政補償", "國家賠償", "刑事補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00273', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '甲女已離婚多年，但前夫仍常藉酒裝瘋上門借錢，若借錢不著則拳打腳踢，連甲母也蒙受其害。在一次激 烈爭吵後，甲母女倆都被打傷，甲女忍無可忍，遂報警處理。依我國法律規定，下列敘述何者正確？', '["若情況急迫，甲女可聲請緊急保護令", "甲母可向法院聲請家暴保護令", "保護令須由家暴受害人親自向檢方聲請", "已離婚的甲女，非家庭暴力防治法保護之對象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00274', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '依司法院釋字第790號解釋，毒品危害防制條例第12條第2項規定：「意圖供製造毒品之用，而栽種大麻 者，處5年以上有期徒刑，得併科新臺幣500萬元以下罰金。」不論行為人犯罪情節之輕重，均處以5年 以上有期徒刑。係違反下列何種原則？', '["明確性原則", "比例原則", "平等原則", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00275', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '甲男患思覺失調，其犯殺人罪後，法院判決無罪，依據犯罪三階段理論，是因為不具備下列何種要件？', '["構成要件該當性", "罪刑法定主義", "違法性", "有責性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
